var e=[{id:`L2_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NULL_NULL`,text:{KOREA:`내가 누구인가는 태어날 때 정해지는 게 아닙니다. 누가 정할 수 있는 것도 아니죠.`,JPN:`自分が何者なのかは、生まれた時に決まるのではありません。他の誰かに決められるものでもありません。`,ENG:`Who I am is not decided by birth. It's not decided by others, either.`,TWN:`我是誰，這不是出生時決定的。也不是被誰決定的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NULL_NULL`,text:{KOREA:`제가 관리국을 위해 싸우는 것도, 사장님을 따르는 것도, 누군가의 명령이 아닌 순전히 제 의지라는 걸 기억해주시기 바랍니다.`,JPN:`私が管理局のために戦うのも、社長に従うのも、誰かの命令ではなく私自身の意志であることをお忘れなきよう。`,ENG:`Please remember I'm fighting for the Administration and following you purely of my own accord.`,TWN:`不管是為管理局戰鬥，還是為了老闆戰鬥，這些都不是任何人的命令，純粹是我自己的意志，希望您能記住這一點。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};